function format(value: string | number | boolean): string {
  if (typeof value === "string") {
    return `"${value}"`;
  }
  if (typeof value === "number") {
    return value.toFixed(2);
  }
  return value ? "yes" : "no";
}

console.log(format("hello"));
console.log(format(3.14159));
console.log(format(true));

class Temperature {
  constructor(public celsius: number) {}
  toFahrenheit(): number { return this.celsius * 9 / 5 + 32; }
}

class Distance {
  constructor(public meters: number) {}
  toKm(): number { return this.meters / 1000; }
}

function describe(measurement: Temperature | Distance): string {
  if (measurement instanceof Temperature) {
    return `${measurement.celsius}°C = ${measurement.toFahrenheit()}°F`;
  }
  return `${measurement.meters}m = ${measurement.toKm()}km`;
}

console.log(describe(new Temperature(100)));
console.log(describe(new Distance(5000)));

interface Cat { name: string; meow(): string; }
interface Dog { name: string; bark(): string; }

function isCat(animal: Cat | Dog): animal is Cat {
  return "meow" in animal;
}

const animals: (Cat | Dog)[] = [
  { name: "Whiskers", meow: () => "Meow!" },
  { name: "Rex",      bark: () => "Woof!" },
  { name: "Luna",     meow: () => "Purrr" },
];

for (const a of animals) {
  if (isCat(a)) {
    console.log(`${a.name}: ${a.meow()}`);
  } else {
    console.log(`${a.name}: ${a.bark()}`);
  }
}
